// Get extracted data
const extractData = $input.first().json;
const taxData = extractData.data || extractData;

// Get trigger data
const triggerData = $('New Document').item.json;
const fileName = triggerData.name || 'unknown';
const fileId = triggerData.id || '';

// Document info
const docType = taxData.documentType || 'Unknown';
const taxYear = taxData.taxYear || new Date().getFullYear().toString();
const source = taxData.source || 'Unknown';
const recipientName = taxData.recipientName || 'N/A';

// Amount and category
const amount = taxData.amount || 0;
const category = taxData.category || 'Other';
const subcategory = taxData.subcategory || 'Other';
const isDeductible = taxData.isDeductible || false;
const deductionType = taxData.deductionType || 'N/A';

// Additional details
const transactionDate = taxData.transactionDate || 'N/A';
const description = taxData.description || '';
const quantity = taxData.quantity || 0;
const unitOfMeasure = taxData.unitOfMeasure || '';

// Determine tax impact
let taxImpact = 'Neutral';
let estimatedTaxEffect = 0;

if (category.toLowerCase().includes('income')) {
  taxImpact = 'Taxable Income';
  // Rough estimate at 25% marginal rate
  estimatedTaxEffect = amount * 0.25;
} else if (isDeductible) {
  taxImpact = 'Tax Deduction';
  // Estimate tax savings at 25% marginal rate
  estimatedTaxEffect = amount * -0.25;
}

// Categorize for Schedule C if self-employment
let scheduleCategory = 'N/A';
if (subcategory.toLowerCase().includes('self-employment') || 
    docType.toLowerCase().includes('1099-nec') ||
    subcategory.toLowerCase().includes('business')) {
  scheduleCategory = 'Schedule C';
} else if (subcategory.toLowerCase().includes('capital')) {
  scheduleCategory = 'Schedule D';
} else if (subcategory.toLowerCase().includes('rental')) {
  scheduleCategory = 'Schedule E';
}

// Filing status helper
let filingNote = '';
if (docType.includes('1099-NEC') && amount > 600) {
  filingNote = 'Self-employment tax applies';
} else if (docType.includes('1099-B')) {
  filingNote = 'Report on Schedule D';
} else if (isDeductible && deductionType === 'itemized') {
  filingNote = 'Only if itemizing deductions';
}

return [{
  json: {
    fileName: fileName,
    fileId: fileId,
    documentType: docType,
    taxYear: taxYear,
    source: source,
    recipientName: recipientName,
    amount: amount,
    category: category,
    subcategory: subcategory,
    isDeductible: isDeductible,
    deductionType: deductionType,
    taxImpact: taxImpact,
    estimatedTaxEffect: estimatedTaxEffect.toFixed(2),
    scheduleCategory: scheduleCategory,
    transactionDate: transactionDate,
    description: description.substring(0, 200),
    quantity: quantity,
    unitOfMeasure: unitOfMeasure,
    filingNote: filingNote,
    processedAt: new Date().toISOString()
  }
}];

